TEST(stash_drop_removes_entry) {
    if (!create_write_test_repo()) {
        TEST_SKIP("Could not create temp test repo");
    }

    GitRepository repo = {};
    if (!git_repo_open(&repo, g_write_test_repo)) {
        cleanup_write_test_repo();
        TEST_SKIP("Could not open temp repo");
    }

    // Create two stashes
    write_test_file(g_write_test_repo, "file1.txt", "first stash\n");
    StashCreateOptions opts1 = {};
    opts1.message = "stash one";
    StashResult res1 = {};
    git_stash_create(&repo, &opts1, &res1);

    write_test_file(g_write_test_repo, "file1.txt", "second stash\n");
    StashCreateOptions opts2 = {};
    opts2.message = "stash two";
    StashResult res2 = {};
    git_stash_create(&repo, &opts2, &res2);

    // Verify we have 2 stashes
    StashEntry entries_before[16];
    size_t count_before = git_stash_list(&repo, entries_before, 16);
    TEST_ASSERT_EQ(count_before, 2);

    // Drop index 0 (stash two - newest)
    StashResult drop_result = {};
    bool success = git_stash_drop(&repo, 0, &drop_result);
    TEST_ASSERT_TRUE(success);

    // Verify only 1 stash remains
    StashEntry entries_after[16];
    size_t count_after = git_stash_list(&repo, entries_after, 16);
    TEST_ASSERT_EQ(count_after, 1);

    // Remaining stash should be "stash one"
    TEST_ASSERT_TRUE(strstr(entries_after[0].message, "stash one") != nullptr);

    git_repo_close(&repo);
    cleanup_write_test_repo();
}

