// ============================================================================
// Section 6: Pathspec / partial stash (Session 4 regressions)
// ============================================================================

// Stashing only one of two dirty files must not wipe the other (S0).
// Covers both unstaged worktree dirt and staged index changes on unselected paths.
TEST(stash_create_selected_preserves_unselected) {
    if (!create_write_test_repo()) {
        TEST_SKIP("Could not create temp test repo");
    }

    GitRepository repo = {};
    if (!git_repo_open(&repo, g_write_test_repo)) {
        cleanup_write_test_repo();
        TEST_SKIP("Could not open temp repo");
    }

    // file1: unstaged (selected for stash)
    write_test_file(g_write_test_repo, "file1.txt", "stashed-only content\n");
    // file2: staged change (NOT selected — must survive in both worktree and index)
    write_test_file(g_write_test_repo, "file2.txt", "must-survive staged content\n");
    TEST_ASSERT_TRUE(git_stage_file(&repo, "file2.txt"));

    // Sanity: file2 is staged before stash
    {
        GitStatus pre = {};
        TEST_ASSERT_TRUE(git_status_compute(&repo, &pre));
        bool file2_staged = false;
        for (size_t i = 0; i < pre.staged_count; i++) {
            if (strcmp(pre.staged[i].path, "file2.txt") == 0) {
                file2_staged = true;
                break;
            }
        }
        git_status_free(&pre);
        TEST_ASSERT_TRUE(file2_staged);
    }

    const char* selected[] = { "file1.txt" };
    StashCreateOptions options = {};
    options.selected_paths = selected;
    options.selected_path_count = 1;
    StashResult result = {};
    TEST_ASSERT_TRUE(git_stash_create(&repo, &options, &result));
    TEST_ASSERT_TRUE(result.success);

    // Selected path restored toward HEAD (not the stashed dirty content)
    size_t size1 = 0;
    char* c1 = read_test_file(g_write_test_repo, "file1.txt", &size1);
    TEST_ASSERT_TRUE(c1 != nullptr);
    TEST_ASSERT_TRUE(strstr(c1, "stashed-only content") == nullptr);
    delete[] c1;

    // Unselected path: worktree content must survive
    size_t size2 = 0;
    char* c2 = read_test_file(g_write_test_repo, "file2.txt", &size2);
    TEST_ASSERT_TRUE(c2 != nullptr);
    TEST_ASSERT_TRUE(strstr(c2, "must-survive staged content") != nullptr);
    delete[] c2;

    // Unselected path: staged index entry must also survive (S0 gap closed)
    {
        GitStatus post = {};
        TEST_ASSERT_TRUE(git_status_compute(&repo, &post));
        bool file2_still_staged = false;
        for (size_t i = 0; i < post.staged_count; i++) {
            if (strcmp(post.staged[i].path, "file2.txt") == 0 &&
                post.staged[i].index_status != GitFileStatus::Unmodified) {
                file2_still_staged = true;
                break;
            }
        }
        // Also accept: still shows as staged modification via index SHA != HEAD
        if (!file2_still_staged) {
            for (size_t i = 0; i < post.staged_count; i++) {
                if (strcmp(post.staged[i].path, "file2.txt") == 0) {
                    file2_still_staged = true;
                    break;
                }
            }
        }
        git_status_free(&post);
        TEST_ASSERT_TRUE(file2_still_staged);
    }

    git_repo_close(&repo);
    cleanup_write_test_repo();
}

// Partial pathspec with include_untracked=false must not delete a selected untracked
// file that was never stored in the stash (only tracked changes were stashed).
TEST(stash_create_selected_keeps_untracked_when_not_included) {
    if (!create_write_test_repo()) {
        TEST_SKIP("Could not create temp test repo");
    }

    GitRepository repo = {};
    if (!git_repo_open(&repo, g_write_test_repo)) {
        cleanup_write_test_repo();
        TEST_SKIP("Could not open temp repo");
    }

    // Tracked change (selected) + untracked file (also in selection list)
    write_test_file(g_write_test_repo, "file1.txt", "tracked-stashed\n");
    write_test_file(g_write_test_repo, "brand_new_untracked.txt", "must-survive-untracked\n");

    const char* selected[] = { "file1.txt", "brand_new_untracked.txt" };
    StashCreateOptions options = {};
    options.selected_paths = selected;
    options.selected_path_count = 2;
    options.include_untracked = false;  // untracked is listed but not stashed

    StashResult result = {};
    TEST_ASSERT_TRUE(git_stash_create(&repo, &options, &result));
    TEST_ASSERT_TRUE(result.success);

    // Untracked file must still exist on disk
    size_t size = 0;
    char* content = read_test_file(g_write_test_repo, "brand_new_untracked.txt", &size);
    TEST_ASSERT_TRUE(content != nullptr);
    TEST_ASSERT_TRUE(strstr(content, "must-survive-untracked") != nullptr);
    delete[] content;

    git_repo_close(&repo);
    cleanup_write_test_repo();
}
